arguments.new_str:
class EnvVarCheck
{
    void CheckFlag()
    {
        // On Linux, set via: export MY_FLAG=""
        // .NET 9 breaking change: empty env vars are no longer treated as unset.
        // Previously GetEnvironmentVariable("MY_FLAG") returned null for export MY_FLAG="".
        // Now it correctly returns "" — use an IDictionary lookup to distinguish
        // "not set" (key absent) from "explicitly empty" (key present, value "").
        var envVars = Environment.GetEnvironmentVariables();
        if (!envVars.Contains("MY_FLAG"))
        {
            Console.WriteLine("MY_FLAG not set, using default");
        }
    }
}

